begin;
create extension if not exists pgtap with schema extensions;
select no_plan();

-- Schema and security.
select has_table('catalog','master_data_audit_events','master audit table exists');
select has_column('catalog','master_data_audit_events','idempotency_command_id','audit links idempotency command');
select has_column('catalog','master_data_audit_events','before_snapshot','audit stores before snapshot');
select has_column('catalog','master_data_audit_events','after_snapshot','audit stores after snapshot');
select has_column('catalog','master_data_audit_events','actor_user_id','audit stores actor');
select has_column('catalog','master_data_audit_events','process_name','audit stores process');
select has_column('catalog','master_data_audit_events','schema_version','audit is schema versioned');
select has_index('catalog','products','uidx_products_org_normalized_sku','normalized Product SKU index exists');
select has_index('catalog','product_batches','uidx_product_batches_org_product_normalized_code','normalized Batch code index exists');
select has_index('catalog','master_data_audit_events','idx_master_data_audit_entity','audit entity index exists');
select has_view('api','product_master','Product master view exists');
select has_view('api','product_batch_master','Batch master view exists');
select has_view('api','product_master_audit','Product audit view exists');
select has_view('api','product_batch_master_audit','Batch audit view exists');
select function_returns('api','create_product',array['uuid','text','text','text','text','text','text']::text[],'jsonb');
select function_returns('api','update_product',array['uuid','text','uuid','bigint','text','text','text','text','text']::text[],'jsonb');
select function_returns('api','archive_product',array['uuid','text','uuid','bigint','text']::text[],'jsonb');
select function_returns('api','reactivate_product',array['uuid','text','uuid','bigint','text']::text[],'jsonb');
select function_returns('api','create_product_batch',array['uuid','text','uuid','text','date','date','timestamp with time zone','text','text']::text[],'jsonb');
select function_returns('api','update_product_batch',array['uuid','text','uuid','bigint','uuid','text','text','date','date','timestamp with time zone','text','text']::text[],'jsonb');
select function_returns('api','block_product_batch',array['uuid','text','uuid','bigint','text','text']::text[],'jsonb');
select function_returns('api','unblock_product_batch',array['uuid','text','uuid','bigint','text','text']::text[],'jsonb');
select function_returns('api','archive_product_batch',array['uuid','text','uuid','bigint','text','text']::text[],'jsonb');
select function_returns('api','reactivate_product_batch',array['uuid','text','uuid','bigint','text','text']::text[],'jsonb');
select is((select count(*) from pg_proc p join pg_namespace n on n.oid=p.pronamespace where n.nspname='api' and p.proname in ('create_product','update_product','archive_product','reactivate_product','create_product_batch','update_product_batch','block_product_batch','unblock_product_batch','archive_product_batch','reactivate_product_batch') and p.prosecdef),10::bigint,'all commands are SECURITY DEFINER');
select is((select count(*) from pg_proc p join pg_namespace n on n.oid=p.pronamespace where n.nspname='api' and p.proname in ('create_product','update_product','archive_product','reactivate_product','create_product_batch','update_product_batch','block_product_batch','unblock_product_batch','archive_product_batch','reactivate_product_batch') and p.proconfig is not null and p.proconfig[1] like 'search_path=%'),10::bigint,'all commands have fixed search_path');
select is((select count(*) from pg_proc p join pg_namespace n on n.oid=p.pronamespace cross join lateral aclexplode(coalesce(p.proacl,acldefault('f',p.proowner))) a where n.nspname='api' and p.proname in ('create_product','update_product','archive_product','reactivate_product','create_product_batch','update_product_batch','block_product_batch','unblock_product_batch','archive_product_batch','reactivate_product_batch') and a.grantee=0 and a.privilege_type='EXECUTE'),0::bigint,'PUBLIC has no command EXECUTE');
select ok((select relrowsecurity from pg_class where oid='catalog.products'::regclass),'Product RLS remains enabled');
select ok((select relrowsecurity from pg_class where oid='catalog.product_batches'::regclass),'Batch RLS remains enabled');
select ok((select relrowsecurity from pg_class where oid='catalog.master_data_audit_events'::regclass),'audit RLS is enabled');
select policies_are('catalog','master_data_audit_events',array['master_data_audit_read_current_org']);
select ok(not has_table_privilege('authenticated','catalog.products','INSERT'),'authenticated cannot insert Product');
select ok(not has_table_privilege('authenticated','catalog.products','UPDATE'),'authenticated cannot update Product');
select ok(not has_table_privilege('authenticated','catalog.products','DELETE'),'authenticated cannot delete Product');
select ok(not has_table_privilege('authenticated','catalog.product_batches','INSERT'),'authenticated cannot insert Batch');
select ok(not has_table_privilege('authenticated','catalog.product_batches','UPDATE'),'authenticated cannot update Batch');
select ok(not has_table_privilege('authenticated','catalog.product_batches','DELETE'),'authenticated cannot delete Batch');
select ok(not has_table_privilege('authenticated','catalog.master_data_audit_events','INSERT'),'authenticated cannot insert audit');
select ok(not has_table_privilege('authenticated','catalog.master_data_audit_events','UPDATE'),'authenticated cannot update audit');
select ok(not has_table_privilege('authenticated','catalog.master_data_audit_events','DELETE'),'authenticated cannot delete audit');
select ok(has_function_privilege('authenticated','api.create_product(uuid,text,text,text,text,text,text)','EXECUTE'),'authenticated may create Product through RPC');
select ok(not has_function_privilege('anon','api.create_product(uuid,text,text,text,text,text,text)','EXECUTE'),'anon cannot create Product');

insert into app.organizations(id,code,name,timezone,is_active,created_at) values
('00000000-0000-4000-8000-000000000053','PGTAP_MASTER_053','pgTAP Master 053','Asia/Jakarta',true,'2026-07-23 08:00:00+07'),
('00000000-0000-4000-8000-000000000054','PGTAP_MASTER_054','pgTAP Other 054','Asia/Makassar',true,'2026-07-23 08:00:00+07');
insert into auth.users(instance_id,id,aud,role,email,email_confirmed_at,raw_app_meta_data,raw_user_meta_data,created_at,updated_at,is_sso_user,is_anonymous) values
('00000000-0000-0000-0000-000000000000','95300000-0000-4000-8000-000000000001','authenticated','authenticated','pgtap.master.053@glowlab.invalid','2026-07-23 08:00:00+07','{"provider":"email","providers":["email"]}'::jsonb,'{}','2026-07-23 08:00:00+07','2026-07-23 08:00:00+07',false,false);
insert into app.user_profiles(user_id,organization_id,display_name,employee_code,role_code,is_active) values
('95300000-0000-4000-8000-000000000001','00000000-0000-4000-8000-000000000053','pgTAP Master Admin','PGTAP-MASTER-053','ADMIN',true);
create temp table master_results(kind text primary key,result jsonb not null) on commit drop;
create temp table master_baseline(phase text primary key,snapshot jsonb not null) on commit drop;
grant select,insert,update on master_results,master_baseline to authenticated;
insert into master_baseline values('ZERO',jsonb_build_object('tx',(select count(*) from inventory.stock_transactions where organization_id='00000000-0000-4000-8000-000000000053'),'ledger',(select count(*) from inventory.stock_ledger_entries where organization_id='00000000-0000-4000-8000-000000000053'),'batch',(select count(*) from inventory.stock_batch_balances where organization_id='00000000-0000-4000-8000-000000000053'),'product',(select count(*) from inventory.stock_product_positions where organization_id='00000000-0000-4000-8000-000000000053'),'reservation',(select count(*) from inventory.stock_reservations where organization_id='00000000-0000-4000-8000-000000000053')));
select set_config('request.jwt.claim.sub','95300000-0000-4000-8000-000000000001',true);
select set_config('request.jwt.claim.role','authenticated',true);
select set_config('request.jwt.claims',jsonb_build_object('sub','95300000-0000-4000-8000-000000000001','role','authenticated','email','pgtap.master.053@glowlab.invalid')::text,true);
set local role authenticated;
-- Product lifecycle and idempotency.
select throws_ok($sql$select api.create_product('00000000-0000-4000-8000-000000000054','053-CROSS','CROSS-053','Cross','UNIT',null,null)$sql$,'42501','ORGANIZATION_ACCESS_DENIED','cross-organization command is denied');
select throws_ok($sql$select api.create_product('00000000-0000-4000-8000-000000000053','053-EMPTY-SKU','   ','Empty','UNIT',null,null)$sql$,'P0001','PRODUCT_REQUIRED_FIELDS_MISSING','blank SKU is rejected');
select throws_ok($sql$select api.create_product('00000000-0000-4000-8000-000000000053','053-EMPTY-NAME','EMPTY-053','   ','UNIT',null,null)$sql$,'P0001','PRODUCT_REQUIRED_FIELDS_MISSING','blank name is rejected');
select throws_ok($sql$select api.create_product('00000000-0000-4000-8000-000000000053','053-BAD-UNIT','BAD-UNIT-053','Bad Unit','BOX',null,null)$sql$,'P0001','UNSUPPORTED_UNIT','unsupported unit is rejected');
insert into master_results select 'P_CREATE',api.create_product('00000000-0000-4000-8000-000000000053','053-P-CREATE','  sku   alpha  053  ','Product Alpha 053',' unit ','Initial description','Initial note');
select is((select result->>'sku' from master_results where kind='P_CREATE'),'SKU ALPHA 053','SKU normalization is deterministic');
select is((select result->>'stockEffect' from master_results where kind='P_CREATE'),'NONE','Product create is stock-neutral');
select is((select (result->>'rowVersion')::bigint from master_results where kind='P_CREATE'),1::bigint,'Product starts version one');
insert into master_results select 'P_REPLAY',api.create_product('00000000-0000-4000-8000-000000000053','053-P-CREATE','  sku   alpha  053  ','Product Alpha 053',' unit ','Initial description','Initial note');
select is((select result->>'productId' from master_results where kind='P_REPLAY'),(select result->>'productId' from master_results where kind='P_CREATE'),'identical Product replay returns same entity');
select is((select count(*) from catalog.products where organization_id='00000000-0000-4000-8000-000000000053'),1::bigint,'Product replay creates one row');
select is((select count(*) from catalog.master_data_audit_events where organization_id='00000000-0000-4000-8000-000000000053' and action_code='PRODUCT_CREATE'),1::bigint,'Product replay creates one audit');
select throws_ok($sql$select api.create_product('00000000-0000-4000-8000-000000000053','053-P-CREATE','SKU ALPHA 053','Changed','UNIT',null,null)$sql$,'P0001','IDEMPOTENCY_KEY_REUSED','changed payload on same key conflicts');
select throws_ok($sql$select api.create_product('00000000-0000-4000-8000-000000000053','053-P-DUP',' sku  alpha 053 ','Duplicate','UNIT',null,null)$sql$,'P0001','DUPLICATE_SKU','normalized duplicate SKU is rejected');
insert into master_results select 'P_UPDATE_PRE',api.update_product('00000000-0000-4000-8000-000000000053','053-P-UPDATE-PRE',(select (result->>'productId')::uuid from master_results where kind='P_CREATE'),1,' sku  beta 053 ','Product Beta 053','UNIT','Before history','Allowed prehistory SKU change');
select is((select result->>'sku' from master_results where kind='P_UPDATE_PRE'),'SKU BETA 053','SKU may change before history');
select is((select (result->>'rowVersion')::bigint from master_results where kind='P_UPDATE_PRE'),2::bigint,'Product update increments row version');
select throws_ok(format($sql$select api.update_product('00000000-0000-4000-8000-000000000053','053-P-STALE','%s',1,'SKU BETA 053','Stale','UNIT',null,null)$sql$,(select result->>'productId' from master_results where kind='P_CREATE')),'P0001','PRODUCT_STALE_VERSION','stale Product update is rejected');
insert into master_results select 'P_SECOND',api.create_product('00000000-0000-4000-8000-000000000053','053-P-SECOND','SECOND 053','Second Product','UNIT',null,null);
insert into master_results select 'P_SECOND_ARCHIVE',api.archive_product('00000000-0000-4000-8000-000000000053','053-P-SECOND-ARCHIVE',(select (result->>'productId')::uuid from master_results where kind='P_SECOND'),1,'Inactive fixture');
select throws_ok(format($sql$select api.create_product_batch('00000000-0000-4000-8000-000000000053','053-INACTIVE-BATCH','%s','INACTIVE LOT','2028-01-01',null,null,'STANDARD',null)$sql$,(select result->>'productId' from master_results where kind='P_SECOND')),'P0001','INACTIVE_PRODUCT_FOR_TRANSACTION','inactive Product cannot receive new Batch');
select is((select snapshot from master_baseline where phase='ZERO'),jsonb_build_object('tx',(select count(*) from inventory.stock_transactions where organization_id='00000000-0000-4000-8000-000000000053'),'ledger',(select count(*) from inventory.stock_ledger_entries where organization_id='00000000-0000-4000-8000-000000000053'),'batch',(select count(*) from inventory.stock_batch_balances where organization_id='00000000-0000-4000-8000-000000000053'),'product',(select count(*) from inventory.stock_product_positions where organization_id='00000000-0000-4000-8000-000000000053'),'reservation',(select count(*) from inventory.stock_reservations where organization_id='00000000-0000-4000-8000-000000000053')),'Product mutations have zero stock-domain delta');
-- Batch create/update and authoritative history.
select throws_ok(format($sql$select api.create_product_batch('00000000-0000-4000-8000-000000000053','053-NO-EXPIRY','%s','NO EXPIRY',null,null,null,'STANDARD',null)$sql$,(select result->>'productId' from master_results where kind='P_CREATE')),'P0001','EXPIRY_DATE_REQUIRED','missing expiry is rejected');
select throws_ok(format($sql$select api.create_product_batch('00000000-0000-4000-8000-000000000053','053-BAD-DATES','%s','BAD DATES','2027-01-01','2027-01-02',null,'STANDARD',null)$sql$,(select result->>'productId' from master_results where kind='P_CREATE')),'P0001','INVALID_BATCH_DATE_RANGE','manufactured after expiry is rejected');
select throws_ok(format($sql$select api.create_product_batch('00000000-0000-4000-8000-000000000053','053-RETURN','%s','RETURN LOT','2028-01-01',null,null,'RETURN',null)$sql$,(select result->>'productId' from master_results where kind='P_CREATE')),'P0001','MANUAL_BATCH_KIND_FORBIDDEN','Admin cannot create RETURN Batch');
select throws_ok(format($sql$select api.create_product_batch('00000000-0000-4000-8000-000000000053','053-UNKNOWN-RETURN','%s','UNKNOWN RETURN','2028-01-01',null,null,'UNIDENTIFIED_RETURN',null)$sql$,(select result->>'productId' from master_results where kind='P_CREATE')),'P0001','MANUAL_BATCH_KIND_FORBIDDEN','Admin cannot create UNIDENTIFIED_RETURN Batch');
insert into master_results select 'B_CREATE',api.create_product_batch('00000000-0000-4000-8000-000000000053','053-B-CREATE',(select (result->>'productId')::uuid from master_results where kind='P_CREATE'),'  lot  alpha 053 ','2027-12-31','2026-01-01',null,'STANDARD','Initial Batch');
select is((select result->>'batchCode' from master_results where kind='B_CREATE'),'LOT ALPHA 053','Batch code normalization is deterministic');
select is((select result->>'batchKindCode' from master_results where kind='B_CREATE'),'STANDARD','Admin Batch kind is STANDARD');
select is((select result->>'stockEffect' from master_results where kind='B_CREATE'),'NONE','Batch create is stock-neutral');
insert into master_results select 'B_REPLAY',api.create_product_batch('00000000-0000-4000-8000-000000000053','053-B-CREATE',(select (result->>'productId')::uuid from master_results where kind='P_CREATE'),'  lot  alpha 053 ','2027-12-31','2026-01-01',null,'STANDARD','Initial Batch');
select is((select result->>'batchId' from master_results where kind='B_REPLAY'),(select result->>'batchId' from master_results where kind='B_CREATE'),'Batch replay returns same entity');
select is((select count(*) from catalog.master_data_audit_events where organization_id='00000000-0000-4000-8000-000000000053' and action_code='BATCH_CREATE'),1::bigint,'Batch replay creates one audit');
select throws_ok(format($sql$select api.create_product_batch('00000000-0000-4000-8000-000000000053','053-B-DUP','%s',' lot alpha  053 ','2028-01-01',null,null,'STANDARD',null)$sql$,(select result->>'productId' from master_results where kind='P_CREATE')),'P0001','DUPLICATE_PRODUCT_BATCH','normalized duplicate Batch is rejected');
select throws_ok(format($sql$select api.update_product_batch('00000000-0000-4000-8000-000000000053','053-B-MOVE','%s',1,'%s','STANDARD','LOT ALPHA 053','2026-01-01','2027-12-31',null,null,null)$sql$,(select result->>'batchId' from master_results where kind='B_CREATE'),(select result->>'productId' from master_results where kind='P_SECOND')),'P0001','BATCH_PRODUCT_CHANGE_FORBIDDEN','Batch product linkage cannot change');
select throws_ok(format($sql$select api.update_product_batch('00000000-0000-4000-8000-000000000053','053-B-KIND','%s',1,'%s','RETURN','LOT ALPHA 053','2026-01-01','2027-12-31',null,null,null)$sql$,(select result->>'batchId' from master_results where kind='B_CREATE'),(select result->>'productId' from master_results where kind='P_CREATE')),'P0001','BATCH_KIND_CHANGE_FORBIDDEN','Batch kind cannot change');
insert into master_results select 'B_UPDATE_PRE',api.update_product_batch('00000000-0000-4000-8000-000000000053','053-B-UPDATE-PRE',(select (result->>'batchId')::uuid from master_results where kind='B_CREATE'),1,(select (result->>'productId')::uuid from master_results where kind='P_CREATE'),'STANDARD',' lot beta 053 ','2026-01-02','2027-12-30',null,null,'Prehistory update');
select is((select (result->>'rowVersion')::bigint from master_results where kind='B_UPDATE_PRE'),2::bigint,'allowed Batch update increments version');
select throws_ok(format($sql$select api.update_product_batch('00000000-0000-4000-8000-000000000053','053-B-STALE','%s',1,'%s','STANDARD','LOT BETA 053','2026-01-02','2027-12-30',null,null,null)$sql$,(select result->>'batchId' from master_results where kind='B_CREATE'),(select result->>'productId' from master_results where kind='P_CREATE')),'P0001','BATCH_STALE_VERSION','stale Batch update is rejected');
insert into master_results select 'RECEIPT',api.post_receipt('00000000-0000-4000-8000-000000000053','053-RECEIPT','RCV-HISTORY-053','2026-07-23 10:00:00+07',jsonb_build_array(jsonb_build_object('productId',(select result->>'productId' from master_results where kind='P_CREATE'),'batchId',(select result->>'batchId' from master_results where kind='B_CREATE'),'quantity',5,'sourceLineRef','HISTORY-1')),'History fixture','{}');
select ok(catalog.product_has_authoritative_history('00000000-0000-4000-8000-000000000053',(select (result->>'productId')::uuid from master_results where kind='P_CREATE')),'Product history helper detects domain history');
select ok(catalog.product_batch_has_authoritative_history('00000000-0000-4000-8000-000000000053',(select (result->>'batchId')::uuid from master_results where kind='B_CREATE')),'Batch history helper detects domain history');
insert into master_baseline values('HISTORY',jsonb_build_object('tx',(select count(*) from inventory.stock_transactions where organization_id='00000000-0000-4000-8000-000000000053'),'ledger',(select count(*) from inventory.stock_ledger_entries where organization_id='00000000-0000-4000-8000-000000000053'),'batch',(select jsonb_agg(to_jsonb(b) order by batch_id) from inventory.stock_batch_balances b where organization_id='00000000-0000-4000-8000-000000000053'),'product',(select jsonb_agg(to_jsonb(p) order by product_id) from inventory.stock_product_positions p where organization_id='00000000-0000-4000-8000-000000000053'),'reservation',(select jsonb_agg(to_jsonb(r) order by id) from inventory.stock_reservations r where organization_id='00000000-0000-4000-8000-000000000053')));
insert into master_results select 'P_RENAME',api.update_product('00000000-0000-4000-8000-000000000053','053-P-RENAME',(select (result->>'productId')::uuid from master_results where kind='P_CREATE'),2,'SKU BETA 053','Product Renamed 053','UNIT','After history','Rename only');
select is((select name from catalog.products where id=(select (result->>'productId')::uuid from master_results where kind='P_CREATE')),'Product Renamed 053','name and description update succeeds');
select is((select after_snapshot->>'name' from catalog.master_data_audit_events where organization_id='00000000-0000-4000-8000-000000000053' and action_code='PRODUCT_CREATE' and entity_id=(select (result->>'productId')::uuid from master_results where kind='P_CREATE')),'Product Alpha 053','historical audit snapshot survives rename');
select is((select product_sku_snapshot from inventory.stock_ledger_entries where organization_id='00000000-0000-4000-8000-000000000053' limit 1),'SKU BETA 053','ledger SKU snapshot remains unchanged');
select throws_ok(format($sql$select api.update_product('00000000-0000-4000-8000-000000000053','053-SKU-HISTORY','%s',3,'SKU GAMMA 053','Forbidden','UNIT',null,null)$sql$,(select result->>'productId' from master_results where kind='P_CREATE')),'P0001','TRANSACTED_SKU_CHANGE_FORBIDDEN','SKU change after history is rejected');
select throws_ok(format($sql$select api.update_product_batch('00000000-0000-4000-8000-000000000053','053-EXPIRY-NO-REASON','%s',3,'%s','STANDARD','LOT BETA 053','2026-01-02','2028-01-31','2026-07-23 10:00:00+07',null,null)$sql$,(select result->>'batchId' from master_results where kind='B_CREATE'),(select result->>'productId' from master_results where kind='P_CREATE')),'P0001','EXPIRY_CHANGE_REASON_REQUIRED','expiry history change requires reason');
insert into master_results select 'B_EXPIRY',api.update_product_batch('00000000-0000-4000-8000-000000000053','053-EXPIRY-REASON',(select (result->>'batchId')::uuid from master_results where kind='B_CREATE'),3,(select (result->>'productId')::uuid from master_results where kind='P_CREATE'),'STANDARD','LOT BETA 053','2026-01-02','2028-01-31','2026-07-23 10:00:00+07','Supplier correction','Audited correction');
select is((select before_snapshot->>'expiryDate' from catalog.master_data_audit_events where id=(select (result->>'auditId')::uuid from master_results where kind='B_EXPIRY')),'2027-12-30','expiry audit stores before');
select is((select after_snapshot->>'expiryDate' from catalog.master_data_audit_events where id=(select (result->>'auditId')::uuid from master_results where kind='B_EXPIRY')),'2028-01-31','expiry audit stores after');
select is((select expiry_date_snapshot from inventory.stock_ledger_entries where organization_id='00000000-0000-4000-8000-000000000053' limit 1),'2027-12-30'::date,'expiry edit preserves ledger snapshot');
-- Lifecycle status, effective expiry, audit immutability, and neutrality.
select throws_ok(format($sql$select api.block_product_batch('00000000-0000-4000-8000-000000000053','053-BLOCK-NO-REASON','%s',4,'   ',null)$sql$,(select result->>'batchId' from master_results where kind='B_CREATE')),'P0001','BATCH_STATUS_REASON_REQUIRED','block requires reason');
insert into master_results select 'B_BLOCK',api.block_product_batch('00000000-0000-4000-8000-000000000053','053-BLOCK',(select (result->>'batchId')::uuid from master_results where kind='B_CREATE'),4,'Quality hold',null);
select is((select lifecycle_status_code from api.product_batch_master where batch_id=(select (result->>'batchId')::uuid from master_results where kind='B_CREATE')),'BLOCKED','Batch becomes BLOCKED');
select isnt((select is_fefo_eligible from api.product_batch_master where batch_id=(select (result->>'batchId')::uuid from master_results where kind='B_CREATE')),true,'BLOCKED Batch is excluded from FEFO');
insert into master_results select 'B_UNBLOCK',api.unblock_product_batch('00000000-0000-4000-8000-000000000053','053-UNBLOCK',(select (result->>'batchId')::uuid from master_results where kind='B_CREATE'),5,'Quality released',null);
select ok((select is_fefo_eligible from api.product_batch_master where batch_id=(select (result->>'batchId')::uuid from master_results where kind='B_CREATE')),'valid unblocked Batch is FEFO eligible');
insert into master_results select 'B_ARCHIVE',api.archive_product_batch('00000000-0000-4000-8000-000000000053','053-B-ARCHIVE',(select (result->>'batchId')::uuid from master_results where kind='B_CREATE'),6,'Archive Batch',null);
select isnt((select is_fefo_eligible from api.product_batch_master where batch_id=(select (result->>'batchId')::uuid from master_results where kind='B_CREATE')),true,'ARCHIVED Batch is excluded from FEFO');
select ok((select has_authoritative_history from api.product_batch_master where batch_id=(select (result->>'batchId')::uuid from master_results where kind='B_CREATE')),'archived Batch remains readable with history');
select is((select count(*) from inventory.stock_ledger_entries where batch_id=(select (result->>'batchId')::uuid from master_results where kind='B_CREATE')),1::bigint,'archived Batch ledger remains visible');
insert into master_results select 'B_REACTIVATE',api.reactivate_product_batch('00000000-0000-4000-8000-000000000053','053-B-REACTIVATE',(select (result->>'batchId')::uuid from master_results where kind='B_CREATE'),7,'Reactivate Batch',null);
insert into master_results select 'REVERSAL_PREVIEW',api.preview_stock_transaction_reversal('00000000-0000-4000-8000-000000000053',(select (result->>'transactionId')::uuid from master_results where kind='RECEIPT'));
insert into master_results select 'REVERSAL_APPLIED',api.reverse_stock_transaction('00000000-0000-4000-8000-000000000053','053-EXACT-REVERSAL',(select (result->>'transactionId')::uuid from master_results where kind='RECEIPT'),(select result->>'basisHash' from master_results where kind='REVERSAL_PREVIEW'),true,'Reverse receipt after expiry correction for snapshot regression.','{"fixture":"product-batch-master-data-expiry-reversal"}'::jsonb);
select is((select result->>'status' from master_results where kind='REVERSAL_APPLIED'),'REVERSED','trusted exact reversal succeeds after Batch expiry correction');
select is((select reversal_of_transaction_id::text from inventory.stock_transactions where id=(select (result->>'reversalTransactionId')::uuid from master_results where kind='REVERSAL_APPLIED')),(select result->>'transactionId' from master_results where kind='RECEIPT'),'exact reversal transaction points to the authoritative receipt');
